window.ZH_PREVIEW_SYNTAX = {"version":"20260614-1","code":{"file":"scripts/build-color-pages.mjs","lang":"js","lineCount":479,"html":"<span class=\"tok-comment\">/*\n * Generates one static, SEO-friendly HTML page per traditional color under /colors/,\n * plus a per-color SVG share card and a site-wide sitemap.xml.\n *\n * Each color page is fully static (content readable without JavaScript) and carries:\n *   - a unique &lt;title&gt;, meta description and canonical URL\n *   - Open Graph / Twitter card tags (image = the real color card PNG)\n *   - JSON-LD structured data (BreadcrumbList + a color CreativeWork)\n *   - the four color value formats (HEX / RGB / HSL / CMYK)\n *   - an internal-link network to related colors via the harmony relations\n *   - entry points into the interactive tools (generator / style-lab / uses)\n *\n * Data is read from the generated browser globals, matching the pattern used by\n * scripts/build-harmony-use-cases.mjs and scripts/build-readme.mjs.\n *\n * Run: node scripts/build-color-pages.mjs\n */</span>\n\n<span class=\"tok-keyword\">import</span> { mkdir, readFile, rm, writeFile } <span class=\"tok-keyword\">from</span> <span class=\"tok-string\">'node:fs/promises'</span>;\n<span class=\"tok-keyword\">import</span> path <span class=\"tok-keyword\">from</span> <span class=\"tok-string\">'node:path'</span>;\n<span class=\"tok-keyword\">import</span> vm <span class=\"tok-keyword\">from</span> <span class=\"tok-string\">'node:vm'</span>;\n<span class=\"tok-keyword\">import</span> { fileURLToPath } <span class=\"tok-keyword\">from</span> <span class=\"tok-string\">'node:url'</span>;\n\n<span class=\"tok-keyword\">const</span> <span class=\"tok-type\">ROOT</span> = path.<span class=\"tok-fn\">resolve</span>(path.<span class=\"tok-fn\">dirname</span>(<span class=\"tok-fn\">fileURLToPath</span>(<span class=\"tok-keyword\">import</span>.meta.url)), <span class=\"tok-string\">'..'</span>);\n<span class=\"tok-keyword\">const</span> <span class=\"tok-type\">IMAGES_FILE</span> = path.<span class=\"tok-fn\">join</span>(<span class=\"tok-type\">ROOT</span>, <span class=\"tok-string\">'assets'</span>, <span class=\"tok-string\">'data'</span>, <span class=\"tok-string\">'images.js'</span>);\n<span class=\"tok-keyword\">const</span> <span class=\"tok-type\">HARMONIES_FILE</span> = path.<span class=\"tok-fn\">join</span>(<span class=\"tok-type\">ROOT</span>, <span class=\"tok-string\">'assets'</span>, <span class=\"tok-string\">'data'</span>, <span class=\"tok-string\">'harmonies.js'</span>);\n<span class=\"tok-keyword\">const</span> <span class=\"tok-type\">USAGE_FILE</span> = path.<span class=\"tok-fn\">join</span>(<span class=\"tok-type\">ROOT</span>, <span class=\"tok-string\">'assets'</span>, <span class=\"tok-string\">'data'</span>, <span class=\"tok-string\">'harmony-usage.js'</span>);\n<span class=\"tok-keyword\">const</span> <span class=\"tok-type\">COLORS_DIR</span> = path.<span class=\"tok-fn\">join</span>(<span class=\"tok-type\">ROOT</span>, <span class=\"tok-string\">'colors'</span>);\n<span class=\"tok-keyword\">const</span> <span class=\"tok-type\">CARDS_DIR</span> = path.<span class=\"tok-fn\">join</span>(<span class=\"tok-type\">COLORS_DIR</span>, <span class=\"tok-string\">'cards'</span>);\n<span class=\"tok-keyword\">const</span> <span class=\"tok-type\">SITEMAP_FILE</span> = path.<span class=\"tok-fn\">join</span>(<span class=\"tok-type\">ROOT</span>, <span class=\"tok-string\">'sitemap.xml'</span>);\n\n<span class=\"tok-keyword\">const</span> <span class=\"tok-type\">SITE</span> = <span class=\"tok-string\">'https://colors.xiaoxiaodong.ai'</span>;\n<span class=\"tok-keyword\">const</span> <span class=\"tok-type\">ASSET_VERSION</span> = <span class=\"tok-string\">'20260614-seo3'</span>;\n\n<span class=\"tok-comment\">// Root-level pages that also belong in the sitemap, with crawl priority hints.</span>\n<span class=\"tok-keyword\">const</span> <span class=\"tok-type\">MAIN_PAGES</span> = [\n  { path: <span class=\"tok-string\">''</span>, priority: <span class=\"tok-string\">'1.0'</span>, changefreq: <span class=\"tok-string\">'weekly'</span> },\n  { path: <span class=\"tok-string\">'explorer.html'</span>, priority: <span class=\"tok-string\">'0.9'</span>, changefreq: <span class=\"tok-string\">'weekly'</span> },\n  { path: <span class=\"tok-string\">'dictionary.html'</span>, priority: <span class=\"tok-string\">'0.9'</span>, changefreq: <span class=\"tok-string\">'weekly'</span> },\n  { path: <span class=\"tok-string\">'palettes.html'</span>, priority: <span class=\"tok-string\">'0.8'</span>, changefreq: <span class=\"tok-string\">'weekly'</span> },\n  { path: <span class=\"tok-string\">'generator.html'</span>, priority: <span class=\"tok-string\">'0.8'</span>, changefreq: <span class=\"tok-string\">'weekly'</span> },\n  { path: <span class=\"tok-string\">'theme-forge.html'</span>, priority: <span class=\"tok-string\">'0.8'</span>, changefreq: <span class=\"tok-string\">'weekly'</span> },\n  { path: <span class=\"tok-string\">'style-lab.html'</span>, priority: <span class=\"tok-string\">'0.8'</span>, changefreq: <span class=\"tok-string\">'weekly'</span> },\n  { path: <span class=\"tok-string\">'gradients.html'</span>, priority: <span class=\"tok-string\">'0.7'</span>, changefreq: <span class=\"tok-string\">'weekly'</span> },\n  { path: <span class=\"tok-string\">'uses.html'</span>, priority: <span class=\"tok-string\">'0.7'</span>, changefreq: <span class=\"tok-string\">'weekly'</span> },\n  { path: <span class=\"tok-string\">'skills.html'</span>, priority: <span class=\"tok-string\">'0.7'</span>, changefreq: <span class=\"tok-string\">'monthly'</span> },\n  <span class=\"tok-comment\">// favorites.html is intentionally excluded: its content is per-visitor</span>\n  <span class=\"tok-comment\">// localStorage, so it is empty for crawlers and marked noindex.</span>\n];\n\n<span class=\"tok-comment\">// Ordered relations rendered on each color page. Mirrors dictionary.js RELATION_TYPES,</span>\n<span class=\"tok-comment\">// but only the eleven that carry shared usage copy in harmony-usage.js drive sections.</span>\n<span class=\"tok-keyword\">const</span> <span class=\"tok-type\">RELATION_TYPES</span> = [\n  { key: <span class=\"tok-string\">'same'</span>, label: <span class=\"tok-string\">'同类'</span> },\n  { key: <span class=\"tok-string\">'analogous'</span>, label: <span class=\"tok-string\">'邻近'</span> },\n  { key: <span class=\"tok-string\">'complementary'</span>, label: <span class=\"tok-string\">'互补'</span> },\n  { key: <span class=\"tok-string\">'splitComplementary'</span>, label: <span class=\"tok-string\">'分裂互补'</span> },\n  { key: <span class=\"tok-string\">'triadic'</span>, label: <span class=\"tok-string\">'三角'</span> },\n  { key: <span class=\"tok-string\">'tetradic'</span>, label: <span class=\"tok-string\">'四角'</span> },\n  { key: <span class=\"tok-string\">'temperatureContrast'</span>, label: <span class=\"tok-string\">'冷暖'</span> },\n  { key: <span class=\"tok-string\">'lighter'</span>, label: <span class=\"tok-string\">'明色'</span> },\n  { key: <span class=\"tok-string\">'darker'</span>, label: <span class=\"tok-string\">'暗色'</span> },\n  { key: <span class=\"tok-string\">'grayTone'</span>, label: <span class=\"tok-string\">'灰调'</span> },\n  { key: <span class=\"tok-string\">'neutral'</span>, label: <span class=\"tok-string\">'中性'</span> },\n];\n\n<span class=\"tok-keyword\">function</span> <span class=\"tok-fn\">loadBrowserData</span>(source, filename) {\n  <span class=\"tok-keyword\">const</span> sandbox = { window: {} };\n  vm.<span class=\"tok-fn\">createContext</span>(sandbox);\n  vm.<span class=\"tok-fn\">runInContext</span>(source, sandbox, { filename });\n  <span class=\"tok-keyword\">return</span> sandbox.window;\n}\n\n<span class=\"tok-keyword\">function</span> <span class=\"tok-fn\">escapeHtml</span>(value) {\n  <span class=\"tok-keyword\">return</span> <span class=\"tok-type\">String</span>(value ?? <span class=\"tok-string\">''</span>).<span class=\"tok-fn\">replace</span>(/[&amp;&lt;&gt;<span class=\"tok-string\">\"']/g, (character) =&gt; ({\n    '&amp;': '&amp;amp;',\n    '&lt;': '&amp;lt;',\n    '&gt;': '&amp;gt;',\n    '\"</span><span class=\"tok-string\">': '</span>&amp;quot;<span class=\"tok-string\">',\n    \"'</span><span class=\"tok-string\">\": '&amp;#39;',\n  })[character]);\n}\n\nfunction colorName(image) {\n  return image.file.replace(/\\.[^.]+$/, '').replace(/^\\d{3}-/, '');\n}\n\nfunction rgbFromHex(hex) {\n  const match = hex?.match(/^#?([0-9a-f]{6})$/i);\n  if (!match) return null;\n  const value = match[1];\n  return {\n    r: Number.parseInt(value.slice(0, 2), 16),\n    g: Number.parseInt(value.slice(2, 4), 16),\n    b: Number.parseInt(value.slice(4, 6), 16),\n  };\n}\n\nfunction hslFromRgb({ r, g, b }) {\n  const red = r / 255;\n  const green = g / 255;\n  const blue = b / 255;\n  const max = Math.max(red, green, blue);\n  const min = Math.min(red, green, blue);\n  const delta = max - min;\n  let hue = 0;\n  let saturation = 0;\n  const lightness = (max + min) / 2;\n\n  if (delta !== 0) {\n    saturation = delta / (1 - Math.abs(2 * lightness - 1));\n    if (max === red) hue = ((green - blue) / delta) % 6;\n    if (max === green) hue = (blue - red) / delta + 2;\n    if (max === blue) hue = (red - green) / delta + 4;\n    hue *= 60;\n    if (hue &lt; 0) hue += 360;\n  }\n\n  return {\n    h: Math.round(hue),\n    s: Math.round(saturation * 100),\n    l: Math.round(lightness * 100),\n  };\n}\n\nfunction cmykFromRgb({ r, g, b }) {\n  const red = r / 255;\n  const green = g / 255;\n  const blue = b / 255;\n  const k = 1 - Math.max(red, green, blue);\n  if (k === 1) return { c: 0, m: 0, y: 0, k: 100 };\n  return {\n    c: Math.round(((1 - red - k) / (1 - k)) * 100),\n    m: Math.round(((1 - green - k) / (1 - k)) * 100),\n    y: Math.round(((1 - blue - k) / (1 - k)) * 100),\n    k: Math.round(k * 100),\n  };\n}\n\n// WCAG relative luminance, used to pick a readable text color over the swatch.\nfunction readableText(hex) {\n  const rgb = rgbFromHex(hex);\n  if (!rgb) return '#111111';\n  const luminance = [rgb.r, rgb.g, rgb.b]\n    .map((channel) =&gt; {\n      const value = channel / 255;\n      return value &lt;= 0.03928 ? value / 12.92 : ((value + 0.055) / 1.055) ** 2.4;\n    })\n    .reduce((sum, value, index) =&gt; sum + value * [0.2126, 0.7152, 0.0722][index], 0);\n  return luminance &gt; 0.5 ? '#1a1a1a' : '#f7f7f4';\n}\n\nfunction lightnessLabel(lightness) {\n  if (lightness &gt;= 82) return '高明度';\n  if (lightness &gt;= 62) return '中高明度';\n  if (lightness &gt;= 42) return '中明度';\n  if (lightness &gt;= 26) return '中低明度';\n  return '低明度';\n}\n\nfunction saturationLabel(saturation) {\n  if (saturation &gt;= 72) return '高饱和';\n  if (saturation &gt;= 42) return '中饱和';\n  if (saturation &gt;= 18) return '低饱和';\n  return '近中性';\n}\n\n// Accurate, data-derived prose (no fabricated historical claims).\nfunction toneNote(hsl, temperature) {\n  if (!hsl) return '色值来自 742 色清单，可作为单色索引和配色锚点。';\n  const notes = [];\n  if (hsl.l &gt;= 84) notes.push('适合留白、背景和轻量层级');\n  else if (hsl.l &lt;= 28) notes.push('适合标题、压重和结构线');\n  else notes.push('适合做主色或稳定辅助色');\n\n  if (hsl.s &gt;= 72) notes.push('高饱和时少量使用更稳');\n  else if (hsl.s &lt;= 18) notes.push('灰调稳定，适合长内容');\n\n  notes.push(`${temperature || '冷暖'}色倾向`);\n  return `${notes.join('，')}。`;\n}\n\n// Builds the value rows from an already-resolved rgb/hsl so the displayed HSL\n// matches the precomputed harmony.hsl used by the meta chips (single source).\nfunction colorValues(hex, rgb, hsl) {\n  if (!rgb) return [{ label: 'HEX', value: hex || '' }];\n  const cmyk = cmykFromRgb(rgb);\n  return [\n    { label: 'HEX', value: hex },\n    { label: 'RGB', value: `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})` },\n    { label: 'HSL', value: hsl ? `hsl(${hsl.h}, ${hsl.s}%, ${hsl.l}%)` : '' },\n    { label: 'CMYK', value: `cmyk(${cmyk.c}%, ${cmyk.m}%, ${cmyk.y}%, ${cmyk.k}%)` },\n  ];\n}\n\n// Page filename / URL slug for a color, e.g. \"</span><span class=\"tok-number\">001</span>-乳白<span class=\"tok-string\">\".\nfunction colorSlug(image) {\n  return `${image.id}-${colorName(image)}`;\n}\n\nfunction colorPageUrl(image) {\n  return `${SITE}/colors/${encodeURIComponent(colorSlug(image))}.html`;\n}\n\nfunction renderColorPage(image, harmony, context) {\n  const { usage, imageById } = context;\n  const name = colorName(image);\n  const hex = image.hex;\n  const ink = readableText(hex);\n  const rgb = rgbFromHex(hex);\n  const hsl = harmony?.hsl || (rgb ? hslFromRgb(rgb) : null);\n  const hueFamily = harmony?.hueFamily || '';\n  const temperature = harmony?.temperature || '';\n  const values = colorValues(hex, rgb, hsl);\n  const slug = colorSlug(image);\n  const canonical = colorPageUrl(image);\n  const ogImage = `${SITE}/${encodeURI(image.path)}`;\n\n  const metaChips = [];\n  if (hueFamily) metaChips.push(hueFamily);\n  if (temperature) metaChips.push(`${temperature}色`);\n  if (hsl) {\n    metaChips.push(lightnessLabel(hsl.l));\n    metaChips.push(saturationLabel(hsl.s));\n  }\n\n  const description = `中国传统色「${name}」的色值与配色：HEX ${hex}`\n    + `${values[1] ? `、${values[1].value}` : ''}`\n    + `${hueFamily ? `，${hueFamily}` : ''}${temperature ? `、${temperature}色调` : ''}。`\n    + `查看同类、邻近、互补等配色关系，并一键用于配色生成、场景试色与用途卡片。`;\n\n  const valuesMarkup = values.map((entry) =&gt; `\n            &lt;button type=\"</span>button<span class=\"tok-string\">\" class=\"</span>color-value<span class=\"tok-string\">\" data-copy-value=\"</span>${<span class=\"tok-fn\">escapeHtml</span>(entry.value)}<span class=\"tok-string\">\" title=\"</span>复制 ${<span class=\"tok-fn\">escapeHtml</span>(entry.label)}<span class=\"tok-string\">\"&gt;\n              &lt;span class=\"</span>color-value-label<span class=\"tok-string\">\"&gt;${escapeHtml(entry.label)}&lt;/span&gt;\n              &lt;span class=\"</span>color-value-text<span class=\"tok-string\">\"&gt;${escapeHtml(entry.value)}&lt;/span&gt;\n            &lt;/button&gt;`).join('');\n\n  const chipsMarkup = metaChips\n    .map((chip) =&gt; `&lt;span class=\"</span>color-chip<span class=\"tok-string\">\"&gt;${escapeHtml(chip)}&lt;/span&gt;`)\n    .join('');\n\n  const relationSections = RELATION_TYPES.map((relation) =&gt; {\n    const ids = Array.isArray(harmony?.[relation.key]) ? harmony[relation.key] : [];\n    const relatedColors = ids\n      .map((id) =&gt; imageById.get(id))\n      .filter(Boolean);\n    if (!relatedColors.length) return '';\n\n    const usageCopy = usage[relation.key];\n    const intent = usageCopy?.intent ? `（${usageCopy.intent}）` : '';\n    const direction = usageCopy?.direction ? `&lt;p class=\"</span>relation-direction<span class=\"tok-string\">\"&gt;${escapeHtml(usageCopy.direction)}&lt;/p&gt;` : '';\n    const swatches = relatedColors.map((related) =&gt; {\n      const relatedHref = `${encodeURIComponent(colorSlug(related))}.html`;\n      return `\n              &lt;a class=\"</span>relation-swatch<span class=\"tok-string\">\" href=\"</span>${relatedHref}<span class=\"tok-string\">\" style=\"</span>--swatch: ${<span class=\"tok-fn\">escapeHtml</span>(related.hex)}; --swatch-ink: ${<span class=\"tok-fn\">readableText</span>(related.hex)};<span class=\"tok-string\">\"&gt;\n                &lt;span class=\"</span>relation-swatch-name<span class=\"tok-string\">\"&gt;${escapeHtml(colorName(related))}&lt;/span&gt;\n                &lt;span class=\"</span>relation-swatch-hex<span class=\"tok-string\">\"&gt;${escapeHtml(related.hex)}&lt;/span&gt;\n              &lt;/a&gt;`;\n    }).join('');\n\n    return `\n          &lt;section class=\"</span>relation-block<span class=\"tok-string\">\"&gt;\n            &lt;h3&gt;${escapeHtml(relation.label)}&lt;span class=\"</span>relation-intent<span class=\"tok-string\">\"&gt;${intent}&lt;/span&gt;&lt;/h3&gt;\n            ${direction}\n            &lt;div class=\"</span>relation-swatches<span class=\"tok-string\">\"&gt;${swatches}&lt;/div&gt;\n          &lt;/section&gt;`;\n  }).filter(Boolean).join('');\n\n  const breadcrumbJsonLd = {\n    '@context': 'https://schema.org',\n    '@type': 'BreadcrumbList',\n    itemListElement: [\n      { '@type': 'ListItem', position: 1, name: '首页', item: `${SITE}/` },\n      { '@type': 'ListItem', position: 2, name: '色彩字典', item: `${SITE}/dictionary.html` },\n      { '@type': 'ListItem', position: 3, name: `${name} ${hex}`, item: canonical },\n    ],\n  };\n\n  const colorJsonLd = {\n    '@context': 'https://schema.org',\n    '@type': 'CreativeWork',\n    name: `${name}`,\n    alternateName: hex,\n    url: canonical,\n    image: ogImage,\n    inLanguage: 'zh-CN',\n    description,\n    color: hex,\n    isPartOf: { '@type': 'CreativeWorkSeries', name: '中国传统色 742 色', url: `${SITE}/dictionary.html` },\n  };\n\n  // JSON-LD is embedded as text; escape the closing tag sequence defensively.\n  const jsonLd = [breadcrumbJsonLd, colorJsonLd]\n    .map((data) =&gt; `&lt;script type=\"</span>application/ld+json<span class=\"tok-string\">\"&gt;${JSON.stringify(data).replace(/&lt;/g, '\\\\u003c')}&lt;/script&gt;`)\n    .join('\\n    ');\n\n  const note = toneNote(hsl, temperature);\n\n  return `&lt;!doctype html&gt;\n&lt;html lang=\"</span>zh-<span class=\"tok-type\">CN</span><span class=\"tok-string\">\"&gt;\n  &lt;head&gt;\n    &lt;meta charset=\"</span>utf-<span class=\"tok-number\">8</span><span class=\"tok-string\">\"&gt;\n    &lt;meta name=\"</span>viewport<span class=\"tok-string\">\" content=\"</span>width=device-width, initial-scale=<span class=\"tok-number\">1</span><span class=\"tok-string\">\"&gt;\n    &lt;meta name=\"</span>description<span class=\"tok-string\">\" content=\"</span>${<span class=\"tok-fn\">escapeHtml</span>(description)}<span class=\"tok-string\">\"&gt;\n    &lt;meta name=\"</span>theme-color<span class=\"tok-string\">\" content=\"</span>#f7f7f4<span class=\"tok-string\">\" data-theme-color&gt;\n    &lt;title&gt;${escapeHtml(`${name} ${hex} - 中国传统色色值与配色 | 中国传统配色`)}&lt;/title&gt;\n    &lt;link rel=\"</span>canonical<span class=\"tok-string\">\" href=\"</span>${<span class=\"tok-fn\">escapeHtml</span>(canonical)}<span class=\"tok-string\">\"&gt;\n    &lt;meta property=\"</span>og:type<span class=\"tok-string\">\" content=\"</span>article<span class=\"tok-string\">\"&gt;\n    &lt;meta property=\"</span>og:site_name<span class=\"tok-string\">\" content=\"</span>中国传统配色<span class=\"tok-string\">\"&gt;\n    &lt;meta property=\"</span>og:title<span class=\"tok-string\">\" content=\"</span>${<span class=\"tok-fn\">escapeHtml</span>(<span class=\"tok-string\">`${name} ${hex} - 中国传统色`</span>)}<span class=\"tok-string\">\"&gt;\n    &lt;meta property=\"</span>og:description<span class=\"tok-string\">\" content=\"</span>${<span class=\"tok-fn\">escapeHtml</span>(description)}<span class=\"tok-string\">\"&gt;\n    &lt;meta property=\"</span>og:url<span class=\"tok-string\">\" content=\"</span>${<span class=\"tok-fn\">escapeHtml</span>(canonical)}<span class=\"tok-string\">\"&gt;\n    &lt;meta property=\"</span>og:image<span class=\"tok-string\">\" content=\"</span>${<span class=\"tok-fn\">escapeHtml</span>(ogImage)}<span class=\"tok-string\">\"&gt;\n    &lt;meta property=\"</span>og:locale<span class=\"tok-string\">\" content=\"</span>zh_CN<span class=\"tok-string\">\"&gt;\n    &lt;meta name=\"</span>twitter:card<span class=\"tok-string\">\" content=\"</span>summary_large_image<span class=\"tok-string\">\"&gt;\n    &lt;meta name=\"</span>twitter:title<span class=\"tok-string\">\" content=\"</span>${<span class=\"tok-fn\">escapeHtml</span>(<span class=\"tok-string\">`${name} ${hex} - 中国传统色`</span>)}<span class=\"tok-string\">\"&gt;\n    &lt;meta name=\"</span>twitter:description<span class=\"tok-string\">\" content=\"</span>${<span class=\"tok-fn\">escapeHtml</span>(description)}<span class=\"tok-string\">\"&gt;\n    &lt;meta name=\"</span>twitter:image<span class=\"tok-string\">\" content=\"</span>${<span class=\"tok-fn\">escapeHtml</span>(ogImage)}<span class=\"tok-string\">\"&gt;\n    &lt;link rel=\"</span>icon<span class=\"tok-string\">\" href=\"</span>../favicon.svg?v=<span class=\"tok-number\">20260610</span>-<span class=\"tok-number\">6</span><span class=\"tok-string\">\" type=\"</span>image/svg+xml<span class=\"tok-string\">\"&gt;\n    ${jsonLd}\n    &lt;script&gt;\n      (() =&gt; {\n        try {\n          const theme = localStorage.getItem('theme');\n          if (theme === 'dark' || theme === 'light') {\n            document.documentElement.dataset.theme = theme;\n          }\n        } catch (error) {\n          document.documentElement.dataset.theme = 'light';\n        }\n      })();\n    &lt;/script&gt;\n    &lt;link rel=\"</span>preconnect<span class=\"tok-string\">\" href=\"</span>https:<span class=\"tok-comment\">//fonts.googleapis.com\"&gt;</span>\n    &lt;link rel=<span class=\"tok-string\">\"preconnect\"</span> href=<span class=\"tok-string\">\"https://fonts.gstatic.com\"</span> crossorigin&gt;\n    &lt;link href=<span class=\"tok-string\">\"https://fonts.googleapis.com/css2?family=M+PLUS+Rounded+1c:wght@400;500;700&amp;family=Noto+Serif+SC:wght@600;700;900&amp;display=swap\"</span> rel=<span class=\"tok-string\">\"stylesheet\"</span>&gt;\n    &lt;link rel=<span class=\"tok-string\">\"stylesheet\"</span> href=<span class=\"tok-string\">\"../assets/css/styles.css?v=20260613-4\"</span>&gt;\n    &lt;link rel=<span class=\"tok-string\">\"stylesheet\"</span> href=<span class=\"tok-string\">\"../assets/css/color-page.css?v=${ASSET_VERSION}\"</span>&gt;\n    &lt;script src=<span class=\"tok-string\">\"https://code.iconify.design/iconify-icon/3.0.0/iconify-icon.min.js\"</span> defer&gt;&lt;/script&gt;\n  &lt;/head&gt;\n  &lt;body data-current-page=<span class=\"tok-string\">\"dictionary\"</span> data-base=<span class=\"tok-string\">\"../\"</span>&gt;\n    &lt;a <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"skip-link\"</span> href=<span class=\"tok-string\">\"#color-main\"</span>&gt;跳到颜色详情&lt;/a&gt;\n\n    &lt;div data-shared-header&gt;&lt;/div&gt;\n\n    &lt;main id=<span class=\"tok-string\">\"color-main\"</span> <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-detail-page\"</span>&gt;\n      &lt;nav <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-breadcrumb\"</span> aria-label=<span class=\"tok-string\">\"面包屑导航\"</span>&gt;\n        &lt;a href=<span class=\"tok-string\">\"../index.html\"</span>&gt;首页&lt;/a&gt;\n        &lt;span aria-hidden=<span class=\"tok-string\">\"true\"</span>&gt;/&lt;/span&gt;\n        &lt;a href=<span class=\"tok-string\">\"../dictionary.html\"</span>&gt;色彩字典&lt;/a&gt;\n        &lt;span aria-hidden=<span class=\"tok-string\">\"true\"</span>&gt;/&lt;/span&gt;\n        &lt;span aria-current=<span class=\"tok-string\">\"page\"</span>&gt;${<span class=\"tok-fn\">escapeHtml</span>(name)}&lt;/span&gt;\n      &lt;/nav&gt;\n\n      &lt;header <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-hero\"</span> style=<span class=\"tok-string\">\"--swatch: ${escapeHtml(hex)}; --swatch-ink: ${ink};\"</span>&gt;\n        &lt;div <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-hero-swatch\"</span> aria-hidden=<span class=\"tok-string\">\"true\"</span>&gt;\n          &lt;span&gt;${<span class=\"tok-fn\">escapeHtml</span>(name)}&lt;/span&gt;\n        &lt;/div&gt;\n        &lt;div <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-hero-copy\"</span>&gt;\n          &lt;p <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-hero-id\"</span>&gt;<span class=\"tok-type\">No</span>.${<span class=\"tok-fn\">escapeHtml</span>(image.id)} / <span class=\"tok-number\">742</span>&lt;/p&gt;\n          &lt;h1&gt;${<span class=\"tok-fn\">escapeHtml</span>(name)}&lt;/h1&gt;\n          &lt;p <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-hero-hex\"</span>&gt;${<span class=\"tok-fn\">escapeHtml</span>(hex)}&lt;/p&gt;\n          &lt;div <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-chips\"</span>&gt;${chipsMarkup}&lt;/div&gt;\n          &lt;p <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-hero-note\"</span>&gt;${<span class=\"tok-fn\">escapeHtml</span>(note)}&lt;/p&gt;\n        &lt;/div&gt;\n      &lt;/header&gt;\n\n      &lt;section <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-section\"</span> aria-labelledby=<span class=\"tok-string\">\"values-title\"</span>&gt;\n        &lt;h2 id=<span class=\"tok-string\">\"values-title\"</span>&gt;色值&lt;/h2&gt;\n        &lt;p <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-section-lede\"</span>&gt;点击任意色值即可复制。&lt;/p&gt;\n        &lt;div <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-values\"</span>&gt;${valuesMarkup}\n        &lt;/div&gt;\n      &lt;/section&gt;\n\n      &lt;section <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-section\"</span> aria-labelledby=<span class=\"tok-string\">\"tools-title\"</span>&gt;\n        &lt;h2 id=<span class=\"tok-string\">\"tools-title\"</span>&gt;用这个颜色继续创作&lt;/h2&gt;\n        &lt;div <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-tools\"</span>&gt;\n          &lt;a <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"button button-primary\"</span> href=<span class=\"tok-string\">\"../generator.html?colors=${encodeURIComponent(hex)}\"</span>&gt;配色生成&lt;/a&gt;\n          &lt;a <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"button button-secondary\"</span> href=<span class=\"tok-string\">\"../style-lab.html?color=${encodeURIComponent(image.id)}\"</span>&gt;场景试色&lt;/a&gt;\n          &lt;a <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"button button-secondary\"</span> href=<span class=\"tok-string\">\"../uses.html?q=${encodeURIComponent(name)}\"</span>&gt;用途卡片&lt;/a&gt;\n          &lt;a <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"button button-secondary\"</span> href=<span class=\"tok-string\">\"../${encodeURI(image.path)}\"</span> download&gt;下载色卡 <span class=\"tok-type\">PNG</span>&lt;/a&gt;\n          &lt;a <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"button button-secondary\"</span> href=<span class=\"tok-string\">\"cards/${escapeHtml(image.id)}.svg\"</span> download=<span class=\"tok-string\">\"${escapeHtml(`${name}-${hex}.svg`)}\"</span>&gt;下载分享卡&lt;/a&gt;\n        &lt;/div&gt;\n      &lt;/section&gt;\n\n      &lt;section <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-section\"</span> aria-labelledby=<span class=\"tok-string\">\"relations-title\"</span>&gt;\n        &lt;h2 id=<span class=\"tok-string\">\"relations-title\"</span>&gt;配色关系&lt;/h2&gt;\n        &lt;p <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-section-lede\"</span>&gt;以「${<span class=\"tok-fn\">escapeHtml</span>(name)}」为锚点，从 <span class=\"tok-number\">742</span> 色库推导的配色方向。点击任意色卡查看它的详情。&lt;/p&gt;\n        &lt;div <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"relation-grid\"</span>&gt;${relationSections}\n        &lt;/div&gt;\n      &lt;/section&gt;\n    &lt;/main&gt;\n\n    &lt;div data-shared-footer&gt;&lt;/div&gt;\n    &lt;div <span class=\"tok-keyword\">class</span>=<span class=\"tok-string\">\"color-toast\"</span> data-toast role=<span class=\"tok-string\">\"status\"</span> aria-live=<span class=\"tok-string\">\"polite\"</span>&gt;&lt;/div&gt;\n\n    &lt;script src=<span class=\"tok-string\">\"../assets/js/shared-chrome.js?v=20260614-4\"</span> defer&gt;&lt;/script&gt;\n    &lt;script src=<span class=\"tok-string\">\"../assets/js/color-page.js?v=${ASSET_VERSION}\"</span> defer&gt;&lt;/script&gt;\n  &lt;/body&gt;\n&lt;/html&gt;\n<span class=\"tok-string\">`;\n}\n\n// A lightweight, on-brand SVG share card per color (downloadable / preview asset).\nfunction renderShareCard(image, harmony) {\n  const name = colorName(image);\n  const hex = image.hex;\n  const ink = readableText(hex);\n  const sub = [harmony?.hueFamily, harmony?.temperature ? `</span>${harmony.temperature}色<span class=\"tok-string\">` : '']\n    .filter(Boolean)\n    .join(' · ');\n  return `</span>&lt;svg xmlns=<span class=\"tok-string\">\"http://www.w3.org/2000/svg\"</span> width=<span class=\"tok-string\">\"1200\"</span> height=<span class=\"tok-string\">\"630\"</span> viewBox=<span class=\"tok-string\">\"0 0 1200 630\"</span> role=<span class=\"tok-string\">\"img\"</span> aria-label=<span class=\"tok-string\">\"${escapeHtml(`${name} ${hex}`)}\"</span>&gt;\n  &lt;rect width=<span class=\"tok-string\">\"1200\"</span> height=<span class=\"tok-string\">\"630\"</span> fill=<span class=\"tok-string\">\"${escapeHtml(hex)}\"</span>/&gt;\n  &lt;text x=<span class=\"tok-string\">\"80\"</span> y=<span class=\"tok-string\">\"120\"</span> font-family=<span class=\"tok-string\">\"'Noto Serif SC', serif\"</span> font-size=<span class=\"tok-string\">\"34\"</span> fill=<span class=\"tok-string\">\"${ink}\"</span> opacity=<span class=\"tok-string\">\"0.78\"</span>&gt;中国传统色 · <span class=\"tok-type\">No</span>.${<span class=\"tok-fn\">escapeHtml</span>(image.id)}&lt;/text&gt;\n  &lt;text x=<span class=\"tok-string\">\"80\"</span> y=<span class=\"tok-string\">\"360\"</span> font-family=<span class=\"tok-string\">\"'Noto Serif SC', serif\"</span> font-size=<span class=\"tok-string\">\"180\"</span> font-weight=<span class=\"tok-string\">\"900\"</span> fill=<span class=\"tok-string\">\"${ink}\"</span>&gt;${<span class=\"tok-fn\">escapeHtml</span>(name)}&lt;/text&gt;\n  &lt;text x=<span class=\"tok-string\">\"80\"</span> y=<span class=\"tok-string\">\"470\"</span> font-family=<span class=\"tok-string\">\"'M PLUS Rounded 1c', sans-serif\"</span> font-size=<span class=\"tok-string\">\"64\"</span> fill=<span class=\"tok-string\">\"${ink}\"</span> letter-spacing=<span class=\"tok-string\">\"4\"</span>&gt;${<span class=\"tok-fn\">escapeHtml</span>(hex)}&lt;/text&gt;\n  &lt;text x=<span class=\"tok-string\">\"80\"</span> y=<span class=\"tok-string\">\"545\"</span> font-family=<span class=\"tok-string\">\"'M PLUS Rounded 1c', sans-serif\"</span> font-size=<span class=\"tok-string\">\"34\"</span> fill=<span class=\"tok-string\">\"${ink}\"</span> opacity=<span class=\"tok-string\">\"0.7\"</span>&gt;${<span class=\"tok-fn\">escapeHtml</span>(sub)}&lt;/text&gt;\n  &lt;text x=<span class=\"tok-string\">\"1120\"</span> y=<span class=\"tok-string\">\"560\"</span> text-anchor=<span class=\"tok-string\">\"end\"</span> font-family=<span class=\"tok-string\">\"'M PLUS Rounded 1c', sans-serif\"</span> font-size=<span class=\"tok-string\">\"30\"</span> fill=<span class=\"tok-string\">\"${ink}\"</span> opacity=<span class=\"tok-string\">\"0.6\"</span>&gt;colors.xiaoxiaodong.ai&lt;/text&gt;\n&lt;/svg&gt;\n<span class=\"tok-string\">`;\n}\n\nfunction renderSitemap(images) {\n  const urls = [];\n  for (const page of MAIN_PAGES) {\n    urls.push({ loc: `</span>${<span class=\"tok-type\">SITE</span>}/${page.path}<span class=\"tok-string\">`, priority: page.priority, changefreq: page.changefreq });\n  }\n  for (const image of images) {\n    urls.push({ loc: colorPageUrl(image), priority: '0.6', changefreq: 'monthly' });\n  }\n  const body = urls.map((url) =&gt; `</span>  &lt;url&gt;\n    &lt;loc&gt;${<span class=\"tok-fn\">escapeHtml</span>(url.loc)}&lt;/loc&gt;\n    &lt;changefreq&gt;${url.changefreq}&lt;/changefreq&gt;\n    &lt;priority&gt;${url.priority}&lt;/priority&gt;\n  &lt;/url&gt;<span class=\"tok-string\">`).join('\\n');\n  return `</span>&lt;?xml version=<span class=\"tok-string\">\"1.0\"</span> encoding=<span class=\"tok-string\">\"UTF-8\"</span>?&gt;\n&lt;urlset xmlns=<span class=\"tok-string\">\"http://www.sitemaps.org/schemas/sitemap/0.9\"</span>&gt;\n${body}\n&lt;/urlset&gt;\n<span class=\"tok-string\">`;\n}\n\nasync function main() {\n  const imagesWindow = loadBrowserData(await readFile(IMAGES_FILE, 'utf8'), IMAGES_FILE);\n  const harmoniesWindow = loadBrowserData(await readFile(HARMONIES_FILE, 'utf8'), HARMONIES_FILE);\n  const usageWindow = loadBrowserData(await readFile(USAGE_FILE, 'utf8'), USAGE_FILE);\n\n  const images = imagesWindow.TRADITIONAL_COLOR_IMAGES || [];\n  const harmonies = harmoniesWindow.TRADITIONAL_COLOR_HARMONIES || {};\n  const usage = usageWindow.TRADITIONAL_COLOR_HARMONY_USAGE || {};\n\n  if (!images.length) throw new Error('No images found in images.js');\n\n  const imageById = new Map(images.map((image) =&gt; [image.id, image]));\n  const context = { usage, imageById };\n\n  // Rebuild the colors directory from scratch so renamed/removed colors never leave stragglers.\n  await rm(COLORS_DIR, { recursive: true, force: true });\n  await mkdir(CARDS_DIR, { recursive: true });\n\n  let written = 0;\n  for (const image of images) {\n    const harmony = harmonies[image.id];\n    const slug = colorSlug(image);\n    await writeFile(path.join(COLORS_DIR, `</span>${slug}.html<span class=\"tok-string\">`), renderColorPage(image, harmony, context), 'utf8');\n    await writeFile(path.join(CARDS_DIR, `</span>${image.id}.svg<span class=\"tok-string\">`), renderShareCard(image, harmony), 'utf8');\n    written += 1;\n  }\n\n  await writeFile(SITEMAP_FILE, renderSitemap(images), 'utf8');\n\n  console.log(`</span><span class=\"tok-type\">Generated</span> ${written} color pages + share cards under colors/<span class=\"tok-string\">`);\n  console.log(`</span><span class=\"tok-type\">Wrote</span> sitemap.xml with ${<span class=\"tok-type\">MAIN_PAGES</span>.length + images.length} <span class=\"tok-type\">URLs</span><span class=\"tok-string\">`);\n}\n\nmain().catch((error) =&gt; {\n  console.error(error);\n  process.exitCode = 1;\n});\n</span>"},"markdown":{"html":"<div class=\"md-h1\">把生成的主题装进 Ghostty</div>\n<div class=\"md-gap\"></div>\n<div class=\"md-p\">挑一个中国传统色作<span class=\"md-strong\">锚色</span>，本工具就为你点名出一整套 16 色 ANSI 调色板——</div>\n<div class=\"md-p\">每个色都是有名有姓的传统色，没有凭空插值的颜色。</div>\n<div class=\"md-gap\"></div>\n<div class=\"md-h2\">三步落地</div>\n<div class=\"md-gap\"></div>\n<div class=\"md-li\"><span class=\"md-bullet\">1.</span> 复制下方 <span class=\"md-code\">Ghostty</span> 配置块</div>\n<div class=\"md-li\"><span class=\"md-bullet\">2.</span> 存成 <span class=\"md-code\">~/.config/ghostty/themes/zhongguo</span></div>\n<div class=\"md-li\"><span class=\"md-bullet\">3.</span> 在 <span class=\"md-code\">config</span> 里写 <span class=\"md-code\">theme = zhongguo</span>，重启即可</div>\n<div class=\"md-gap\"></div>\n<div class=\"md-quote\">提示：所有 <span class=\"md-code\">*-foreground</span> 与背景的对比度都过了 <span class=\"md-strong\">WCAG AA</span>，</div>\n<div class=\"md-quote\">注释灰也保证「暗而可辨」，长时间盯着不累眼。</div>\n<div class=\"md-gap\"></div>\n<div class=\"md-codeblock\"><span class=\"tok-comment\">// 锚色 → 调色板，全程 snap 真实命名色</span>\n<span class=\"tok-keyword\">const</span> palette = <span class=\"tok-type\">ZH_TERMINAL</span>.<span class=\"tok-fn\">build</span>(anchorId, <span class=\"tok-string\">'dark'</span>);\n<span class=\"tok-keyword\">for</span> (<span class=\"tok-keyword\">const</span> slot <span class=\"tok-keyword\">of</span> palette.slots) {\n  <span class=\"tok-keyword\">if</span> (slot.nudged) console.<span class=\"tok-fn\">warn</span>(<span class=\"tok-string\">'算法兜底:'</span>, slot.key);\n}</div>\n<div class=\"md-gap\"></div>\n<div class=\"md-p\">想换一套？回到<span class=\"md-link\">色卡库</span>再点一个锚色就好。</div>"}};
